186→fn resolve_data_dir(data_dir: &PathBuf) -> anyhow::Result<PathBuf> {
187→    let workspace_root = std::env::current_dir()?;
188→    Ok(if data_dir.is_relative() {
189→        workspace_root.join(data_dir)
190→    } else {
191→        data_dir.clone()
192→    })
193→}
194→
195→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
196→    let path = data_dir.join("last_session");
197→    let raw = std::fs::read_to_string(path).ok()?;
198→    let session = raw.trim();
199→    if session.is_empty() {
200→        None
201→    } else {
202→        Some(session.to_owned())
203→    }
204→}
205→
206→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
207→    std::fs::create_dir_all(data_dir)?;
208→    std::fs::write(data_dir.join("last_session"), session)?;
209→    Ok(())
210→}
211→
212→async fn most_recent_session_from_journal(data_dir: &Path) -> anyhow::Result<Option<String>> {
213→    let journal_path = data_dir.join("journal.redb");
214→    if !journal_path.exists() {
215→        return Ok(None);
216→    }
217→
218→    let journal = RedbJournal::open(&journal_path)?;
219→
220→    // Preferred path when sessions are indexed in Lago.
221→    let sessions = journal.list_sessions().await?;
222→    if let Some(session) = sessions.into_iter().max_by_key(|entry| entry.created_at) {
223→        return Ok(Some(session.session_id.to_string()));
224→    }
225→
226→    // Fallback for runtime paths that only append events.
227→    let events = journal.read(EventQuery::new()).await?;
228→    Ok(events
229→        .into_iter()
230→        .max_by_key(|event| event.timestamp)
231→        .map(|event| event.session_id.to_string()))
232→}
233→
234→async fn resolve_chat_session(data_dir: &Path, requested: Option<String>) -> String {
235→    if let Some(session) = requested {
236→        return session;
237→    }
238→
239→    if let Some(session) = read_last_session_hint(data_dir) {
240→        return session;
241→    }
242→
243→    match most_recent_session_from_journal(data_dir).await {
244→        Ok(Some(session)) => return session,
245→        Ok(None) => {}
246→        Err(error) => tracing::warn!(%error, "failed to detect most recent session from journal"),
247→    }
248→
249→    "default".to_owned()
250→}
