165→async fn shutdown_signal() {
166→    let ctrl_c = tokio::signal::ctrl_c();
167→
168→    #[cfg(unix)]
169→    {
170→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
171→            .expect("failed to install SIGTERM handler");
172→        tokio::select! {
173→            _ = ctrl_c => {},
174→            _ = sigterm.recv() => {},
175→        }
176→    }
177→
178→    #[cfg(not(unix))]
179→    {
180→        ctrl_c.await.ok();
181→    }
182→
183→    tracing::info!("Received shutdown signal, draining connections...");
184→}
