252→fn run_serve(
253→    data_dir: &Path,
254→    port: u16,
255→    _max_iterations: u32,
256→    _approval_timeout: u64,
257→) -> anyhow::Result<()> {
258→    let workspace_root = std::env::current_dir()?;
259→
260→    // --- Lago persistence ---
261→    let journal_path = data_dir.join("journal.redb");
262→    let blobs_path = data_dir.join("blobs");
263→    std::fs::create_dir_all(&blobs_path)?;
264→
265→    tracing::info!(
266→        workspace = %workspace_root.display(),
267→        journal = %journal_path.display(),
268→        blobs = %blobs_path.display(),
269→        "Starting arcan"
270→    );
271→
272→    let journal = RedbJournal::open(&journal_path)?;
273→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
274→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
275→
276→    // --- Policies ---
277→    let fs_policy = FsPolicy::new(workspace_root.clone());
278→    let sandbox_policy = SandboxPolicy {
279→        workspace_root: workspace_root.clone(),
280→        shell_enabled: true,
281→        network: NetworkPolicy::AllowAll,
282→        allowed_env: BTreeSet::new(),
283→        max_execution_ms: 10_000,
284→        max_stdout_bytes: 1024 * 1024,
285→        max_stderr_bytes: 1024 * 1024,
286→        max_processes: 10,
287→        max_memory_mb: 512,
288→    };
289→
290→    // --- Tools ---
291→    let mut registry = ToolRegistry::default();
292→    registry.register(ReadFileTool::new(fs_policy.clone()));
293→    registry.register(WriteFileTool::new(fs_policy.clone()));
294→    registry.register(ListDirTool::new(fs_policy.clone()));
295→    registry.register(EditFileTool::new(fs_policy.clone()));
296→    registry.register(GlobTool::new(fs_policy.clone()));
297→    registry.register(GrepTool::new(fs_policy));
298→
299→    let runner = Box::new(LocalCommandRunner);
300→    registry.register(BashTool::new(sandbox_policy, runner));
301→
302→    let memory_dir = data_dir.join("memory");
303→    std::fs::create_dir_all(&memory_dir)?;
304→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
305→    registry.register(WriteMemoryTool::new(memory_dir));
306→
307→    // --- Governed memory tools (event-sourced via Lago) ---
308→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
309→    registry.register(MemoryQueryTool::new(memory_projection));
310→    registry.register(MemoryProposeTool::new(journal.clone()));
311→    registry.register(MemoryCommitTool::new(journal.clone()));
312→
313→    // --- Provider ---
314→    // Selection order: ARCAN_PROVIDER env var > auto-detect from API keys > MockProvider
315→    let provider_name = std::env::var("ARCAN_PROVIDER").unwrap_or_default();
316→    let provider: Arc<dyn Provider> = match provider_name.as_str() {
317→        "mock" => {
318→            tracing::warn!("Provider: MockProvider (forced via ARCAN_PROVIDER=mock)");
319→            Arc::new(MockProvider)
320→        }
321→        "openai" => match arcan_provider::openai::OpenAiConfig::openai_from_env() {
322→            Ok(config) => {
323→                tracing::info!(model = %config.model, "Provider: OpenAI");
324→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
325→                    config,
326→                ))
327→            }
328→            Err(e) => {
329→                tracing::error!("ARCAN_PROVIDER=openai but config failed: {e}");
330→                return Err(e.into());
331→            }
332→        },
333→        "ollama" => match arcan_provider::openai::OpenAiConfig::ollama_from_env() {
334→            Ok(config) => {
335→                tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
336→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
337→                    config,
338→                ))
339→            }
340→            Err(e) => {
341→                tracing::error!("ARCAN_PROVIDER=ollama but config failed: {e}");
342→                return Err(e.into());
343→            }
344→        },
345→        "anthropic" => match AnthropicConfig::from_env() {
346→            Ok(config) => {
347→                tracing::info!(model = %config.model, "Provider: Anthropic");
348→                Arc::new(AnthropicProvider::new(config))
349→            }
350→            Err(e) => {
351→                tracing::error!("ARCAN_PROVIDER=anthropic but config failed: {e}");
352→                return Err(e.into());
353→            }
354→        },
355→        // Auto-detect: try providers in order
356→        _ => {
357→            if let Ok(config) = AnthropicConfig::from_env() {
358→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
359→                Arc::new(AnthropicProvider::new(config))
360→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
361→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
362→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
363→                    config,
364→                ))
365→            } else {
366→                tracing::warn!(
367→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
368→                );
369→                Arc::new(MockProvider)
370→            }
371→        }
372→    };
373→
374→    // --- Canonical aiOS runtime adapters ---
375→    let event_store: Arc<dyn EventStorePort> =
376→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
377→    let provider_adapter: Arc<dyn ModelProviderPort> =
378→        Arc::new(ArcanProviderAdapter::new(provider, registry.definitions()));
379→    let observer = Arc::new(LakeFsObserver {
380→        workspace_root: workspace_root.clone(),
381→        journal: journal.clone(),
382→        blob_store: _blob_store,
383→    });
384→    let tool_harness: Arc<dyn ToolHarnessPort> =
385→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
386→    let policy_gate: Arc<dyn PolicyGatePort> =
387→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
388→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
389→
390→    let runtime = Arc::new(KernelRuntime::new(
391→        RuntimeConfig::new(data_dir.to_path_buf()),
392→        event_store,
393→        provider_adapter,
394→        tool_harness,
395→        approvals,
396→        policy_gate,
397→    ));
398→
399→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
400→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
401→        .enable_all()
402→        .build()?;
403→
404→    tokio_runtime.block_on(async move {
405→        // --- HTTP Server ---
406→        let router = create_canonical_router(runtime);
407→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
408→        let listener = TcpListener::bind(addr).await?;
409→
410→        tracing::info!(%addr, "Listening");
411→        axum::serve(listener, router)
412→            .with_graceful_shutdown(shutdown_signal())
413→            .await?;
414→
415→        tracing::info!("Server shut down gracefully");
416→        Ok(())
417→    })
418→}
419→
420→async fn run_chat(
421→    data_dir: PathBuf,
422→    port: u16,
423→    session: Option<String>,
424→    url: Option<String>,
425→) -> anyhow::Result<()> {
426→    let session = resolve_chat_session(&data_dir, session).await;
427→    tracing::info!(session = %session, "launching TUI");
428→    let base_url = match url {
429→        Some(u) => u,
430→        None => daemon::ensure_daemon(&data_dir, port).await?,
431→    };
432→
433→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
434→        tracing::warn!(%error, "failed to persist last_session hint");
435→    }
436→
437→    arcan_tui::run_tui(base_url, session).await
438→}
439→
440→fn main() -> anyhow::Result<()> {
441→    let cli = Cli::parse();
442→    let data_dir = resolve_data_dir(&cli.data_dir)?;
443→
444→    match cli.command {
445→        Some(Command::Serve {
446→            max_iterations,
447→            approval_timeout,
448→        }) => {
449→            // Structured logging to stderr for daemon mode
450→            tracing_subscriber::fmt()
451→                .with_env_filter(EnvFilter::from_default_env())
452→                .init();
453→
454→            run_serve(&data_dir, cli.port, max_iterations, approval_timeout)
455→        }
456→        Some(Command::Chat { session, url }) => {
457→            // File-based logging for TUI mode (don't clobber the terminal)
458→            let log_dir = data_dir.join("logs");
459→            std::fs::create_dir_all(&log_dir)?;
460→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
461→            tracing_subscriber::fmt()
462→                .with_writer(file_appender)
463→                .with_env_filter(EnvFilter::from_default_env())
464→                .init();
465→
466→            let runtime = tokio::runtime::Builder::new_multi_thread()
467→                .enable_all()
468→                .build()?;
469→            runtime.block_on(run_chat(data_dir, cli.port, session, url))
470→        }
471→        None => {
472→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
473→            let log_dir = data_dir.join("logs");
474→            std::fs::create_dir_all(&log_dir)?;
475→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
476→            tracing_subscriber::fmt()
477→                .with_writer(file_appender)
478→                .with_env_filter(EnvFilter::from_default_env())
479→                .init();
480→
481→            let runtime = tokio::runtime::Builder::new_multi_thread()
482→                .enable_all()
483→                .build()?;
484→            runtime.block_on(run_chat(data_dir, cli.port, None, None))
485→        }
486→    }
487→}
