184→fn run_stop_reason_from_string(reason: &str) -> RunStopReason {
185→    match reason {
186→        "completed" => RunStopReason::Completed,
187→        "needs_user" => RunStopReason::NeedsUser,
188→        "blocked_by_policy" => RunStopReason::BlockedByPolicy,
189→        "budget_exceeded" => RunStopReason::BudgetExceeded,
190→        "cancelled" => RunStopReason::Cancelled,
191→        _ => RunStopReason::Error,
192→    }
193→}
