244→async fn get_state(
245→    Path(session_id): Path<String>,
246→    Query(query): Query<EventQuery>,
247→    State(state): State<CanonicalState>,
248→) -> Result<Json<StateResponse>, (StatusCode, Json<serde_json::Value>)> {
249→    let session_id = SessionId::from_string(session_id);
250→    let branch = query
251→        .branch
252→        .as_deref()
253→        .map(BranchId::from_string)
254→        .unwrap_or_else(BranchId::main);
255→    let events = state
256→        .runtime
257→        .read_events_on_branch(&session_id, &branch, 1, 4096)
258→        .await
259→        .map_err(internal_error)?;
260→
261→    let mut latest_state = AgentStateVector::default();
262→    let mut mode = OperatingMode::Explore;
263→    let mut version = 0_u64;
264→    for event in events {
265→        version = event.sequence;
266→        if let EventKind::StateEstimated {
267→            state,
268→            mode: event_mode,
269→        } = event.kind
270→        {
271→            latest_state = state;
272→            mode = event_mode;
273→        }
274→    }
275→
276→    Ok(Json(StateResponse {
277→        session_id,
278→        branch,
279→        mode,
280→        state: latest_state,
281→        version,
282→    }))
