313→async fn stream_events(
314→    Path(session_id): Path<String>,
315→    Query(query): Query<StreamQuery>,
316→    State(state): State<CanonicalState>,
317→) -> Result<Response, (StatusCode, Json<serde_json::Value>)> {
318→    let session_id = SessionId::from_string(session_id);
319→    let format = StreamFormat::from_query(query.format.as_deref());
320→    let branch = query
321→        .branch
322→        .as_deref()
323→        .map(BranchId::from_string)
324→        .unwrap_or_else(BranchId::main);
325→    let cursor = query.cursor.unwrap_or(0);
326→    let replay_limit = query.replay_limit.unwrap_or(512).min(10_000);
327→
328→    let replay = state
329→        .runtime
330→        .read_events_on_branch(&session_id, &branch, cursor.saturating_add(1), replay_limit)
331→        .await
332→        .map_err(internal_error)?;
333→
334→    let mut subscription = state.runtime.subscribe_events();
335→    let (tx, rx) = mpsc::channel::<EventRecord>(256);
336→    let session_filter = session_id.clone();
337→    let branch_filter = branch.clone();
338→
339→    tokio::spawn(async move {
340→        for event in replay {
341→            let _ = tx.send(event).await;
342→        }
343→        while let Ok(event) = subscription.recv().await {
344→            if event.session_id == session_filter
345→                && event.branch_id == branch_filter
346→                && event.sequence > cursor
347→            {
348→                let _ = tx.send(event).await;
349→            }
350→        }
351→    });
352→
353→    let stream = ReceiverStream::new(rx).map(move |event| {
354→        let base = Event::default().id(event.sequence.to_string());
355→        let frame = match format {
356→            StreamFormat::Canonical => {
357→                let payload = serde_json::to_string(&event).unwrap_or_else(|_| "{}".to_owned());
358→                base.data(payload)
359→            }
360→            StreamFormat::VercelAiSdkV6 => {
361→                let payload =
362→                    serde_json::to_string(&json!({ "type": "data-aios-event", "data": event }))
363→                        .unwrap_or_else(|_| "{}".to_owned());
364→                base.data(payload)
365→            }
366→        };
367→        Ok::<Event, Infallible>(frame)
368→    });
369→
370→    let sse = Sse::new(stream).keep_alive(KeepAlive::new().interval(Duration::from_secs(15)));
371→    let mut response = sse.into_response();
372→    if format == StreamFormat::VercelAiSdkV6 {
373→        response.headers_mut().insert(
374→            "x-vercel-ai-ui-message-stream",
375→            "v1".parse().expect("static header value"),
376→        );
377→    }
378→    Ok(response)
379→}
