168→    /// Read events matching a query in a read transaction.
169→    fn read_blocking(db: &Database, query: EventQuery) -> LagoResult<Vec<EventEnvelope>> {
170→        let txn = db
171→            .begin_read()
172→            .map_err(|e| LagoError::Journal(format!("begin_read failed: {e}")))?;
173→        let events_table = txn
174→            .open_table(EVENTS)
175→            .map_err(|e| LagoError::Journal(format!("open events table: {e}")))?;
176→
177→        let mut results = Vec::new();
178→
179→        // Build the key range based on query parameters
180→        match (&query.session_id, &query.branch_id) {
181→            (Some(session_id), Some(branch_id)) => {
182→                // Specific session + branch: scan within that prefix
183→                let after = query.after_seq.unwrap_or(0);
184→                let before = query.before_seq.unwrap_or(u64::MAX);
185→                let start_key = encode_event_key(session_id.as_str(), branch_id.as_str(), after);
186→                let end_key = encode_event_key(session_id.as_str(), branch_id.as_str(), before);
187→
188→                let range = events_table
189→                    .range(start_key.as_slice()..=end_key.as_slice())
190→                    .map_err(|e| LagoError::Journal(format!("range scan: {e}")))?;
191→
192→                for item in range {
193→                    let (_, value) =
194→                        item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
195→                    let envelope: EventEnvelope = serde_json::from_str(value.value())?;
196→
197→                    // Filter: after_seq is exclusive
198→                    if let Some(after_seq) = query.after_seq
199→                        && envelope.seq <= after_seq
200→                    {
201→                        continue;
202→                    }
203→                    // Filter: before_seq is exclusive
204→                    if let Some(before_seq) = query.before_seq
205→                        && envelope.seq >= before_seq
206→                    {
207→                        continue;
208→                    }
209→
210→                    results.push(envelope);
211→                    if let Some(limit) = query.limit
212→                        && results.len() >= limit
213→                    {
214→                        break;
215→                    }
216→                }
217→            }
218→            (Some(session_id), None) => {
219→                // All branches for a session: scan the session prefix.
220→                // Start key = session_id + min_branch + 0
221→                // End key   = session_id + max_branch + u64::MAX
222→                let start_key = encode_event_key(session_id.as_str(), "", 0);
223→                // Use a key that is just past all valid branch IDs for this session
224→                let mut end_prefix = vec![0xFFu8; crate::keys::EVENT_KEY_LEN];
225→                let sid_bytes = session_id.as_str().as_bytes();
226→                let copy_len = sid_bytes.len().min(26);
227→                end_prefix[..copy_len].copy_from_slice(&sid_bytes[..copy_len]);
228→
229→                let range = events_table
230→                    .range(start_key.as_slice()..=end_prefix.as_slice())
231→                    .map_err(|e| LagoError::Journal(format!("range scan: {e}")))?;
232→
233→                for item in range {
234→                    let (_, value) =
235→                        item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
236→                    let envelope: EventEnvelope = serde_json::from_str(value.value())?;
237→
238→                    if let Some(after_seq) = query.after_seq
239→                        && envelope.seq <= after_seq
240→                    {
241→                        continue;
242→                    }
243→                    if let Some(before_seq) = query.before_seq
244→                        && envelope.seq >= before_seq
245→                    {
246→                        continue;
247→                    }
248→
249→                    results.push(envelope);
250→                    if let Some(limit) = query.limit
251→                        && results.len() >= limit
252→                    {
253→                        break;
254→                    }
255→                }
256→            }
257→            (None, _) => {
258→                // Full scan (no session filter)
259→                let range = events_table
260→                    .iter()
261→                    .map_err(|e| LagoError::Journal(format!("iter: {e}")))?;
262→
263→                for item in range {
264→                    let (_key, value) =
265→                        item.map_err(|e| LagoError::Journal(format!("range item: {e}")))?;
266→                    let json_str: &str = value.value();
267→                    let envelope: EventEnvelope = serde_json::from_str(json_str)?;
268→
269→                    if let Some(ref sid) = query.session_id
270→                        && envelope.session_id.as_str() != sid.as_str()
271→                    {
272→                        continue;
273→                    }
274→                    if let Some(ref bid) = query.branch_id
275→                        && envelope.branch_id.as_str() != bid.as_str()
276→                    {
277→                        continue;
278→                    }
279→                    if let Some(after_seq) = query.after_seq
280→                        && envelope.seq <= after_seq
281→                    {
282→                        continue;
283→                    }
284→                    if let Some(before_seq) = query.before_seq
285→                        && envelope.seq >= before_seq
286→                    {
287→                        continue;
288→                    }
289→
290→                    results.push(envelope);
291→                    if let Some(limit) = query.limit
292→                        && results.len() >= limit
293→                    {
294→                        break;
295→                    }
296→                }
297→            }
298→        }
299→
300→        Ok(results)
301→    }
