303→    /// Get a single event by its EventId via the index table.
304→    fn get_event_blocking(db: &Database, event_id: &str) -> LagoResult<Option<EventEnvelope>> {
305→        let txn = db
306→            .begin_read()
307→            .map_err(|e| LagoError::Journal(format!("begin_read failed: {e}")))?;
308→
309→        let index_table = txn
310→            .open_table(EVENT_INDEX)
311→            .map_err(|e| LagoError::Journal(format!("open event_index table: {e}")))?;
312→
313→        let compound_key = match index_table
314→            .get(event_id)
315→            .map_err(|e| LagoError::Journal(format!("get event index: {e}")))?
316→        {
317→            Some(v) => v.value().to_vec(),
318→            None => return Ok(None),
319→        };
320→
321→        let events_table = txn
322→            .open_table(EVENTS)
323→            .map_err(|e| LagoError::Journal(format!("open events table: {e}")))?;
324→
325→        match events_table
326→            .get(compound_key.as_slice())
327→            .map_err(|e| LagoError::Journal(format!("get event: {e}")))?
328→        {
329→            Some(v) => {
330→                let envelope: EventEnvelope = serde_json::from_str(v.value())?;
331→                Ok(Some(envelope))
332→            }
333→            None => Ok(None),
334→        }
335→    }
