 7→
 8→/// Run the Lago daemon with the given configuration.
 9→pub async fn run(config: DaemonConfig) -> Result<(), Box<dyn std::error::Error>> {
10→    info!(?config, "starting lagod");
11→
12→    // --- Ensure data directory exists
13→    std::fs::create_dir_all(&config.data_dir)?;
14→
15→    // --- Load policy engine
16→    if config.policy_path.exists() {
17→        let policy_config = lago_policy::PolicyConfig::load(&config.policy_path)?;
18→        let (engine, rbac, runner) = policy_config.into_engine();
19→        info!(
20→            rules = engine.rules().len(),
21→            roles = rbac.roles().len(),
22→            hooks = runner.hooks().len(),
23→            path = %config.policy_path.display(),
24→            "policy engine loaded"
25→        );
26→        // TODO: Inject engine/rbac/runner into AppState once policy middleware is wired into HTTP routes
27→        let _ = (engine, rbac, runner);
28→    } else {
29→        info!(
30→            path = %config.policy_path.display(),
31→            "no policy file found, running without policy enforcement"
32→        );
33→    }
34→
35→    // --- Open the redb journal
36→    let db_path = config.data_dir.join("journal.redb");
37→    let journal = lago_journal::RedbJournal::open(&db_path)?;
38→    let journal = Arc::new(journal);
39→    info!(path = %db_path.display(), "journal opened");
40→
41→    // --- Open the blob store
42→    let blobs_path = config.data_dir.join("blobs");
43→    let blob_store = lago_store::BlobStore::open(&blobs_path)?;
44→    let blob_store = Arc::new(blob_store);
45→    info!(path = %blobs_path.display(), "blob store opened");
46→
47→    // --- Start gRPC server
48→    let grpc_addr: std::net::SocketAddr = format!("0.0.0.0:{}", config.grpc_port).parse()?;
49→    let ingest_server = lago_ingest::IngestServer::new(journal.clone());
50→    let grpc_service =
51→        lago_ingest::proto::ingest_service_server::IngestServiceServer::new(ingest_server);
52→
53→    info!(%grpc_addr, "starting gRPC server");
54→    let grpc_handle = tokio::spawn(async move {
55→        tonic::transport::Server::builder()
56→            .add_service(grpc_service)
57→            .serve(grpc_addr)
58→            .await
59→            .map_err(|e| format!("gRPC server error: {e}"))
60→    });
61→
62→    // --- Start HTTP server
63→    let http_addr: std::net::SocketAddr = format!("0.0.0.0:{}", config.http_port).parse()?;
64→    let state = lago_api::AppState {
65→        journal: journal.clone() as Arc<dyn lago_core::Journal>,
66→        blob_store: blob_store.clone(),
67→        data_dir: config.data_dir.clone(),
68→    };
69→    let app = lago_api::build_router(Arc::new(state));
70→    let listener = tokio::net::TcpListener::bind(http_addr).await?;
71→
72→    info!(%http_addr, "starting HTTP server");
73→    let http_handle = tokio::spawn(async move {
74→        axum::serve(listener, app)
75→            .await
76→            .map_err(|e| format!("HTTP server error: {e}"))
77→    });
78→
79→    info!("lagod is ready");
80→
81→    // --- Wait for shutdown signal
82→    shutdown::shutdown_signal().await;
83→    info!("shutdown signal received");
84→
85→    // Abort both servers
86→    grpc_handle.abort();
87→    http_handle.abort();
88→
89→    // Wait for tasks to finish (they may have already been aborted)
90→    let _ = grpc_handle.await;
91→    let _ = http_handle.await;
92→
93→    info!("lagod stopped");
94→    Ok(())
95→}
