 1→/// Returns a future that resolves when the process receives a shutdown signal
 2→/// (SIGINT on all platforms, plus SIGTERM on Unix).
 3→///
 4→/// This is used to coordinate graceful shutdown of the gRPC and HTTP servers.
 5→pub async fn shutdown_signal() {
 6→    let ctrl_c = tokio::signal::ctrl_c();
 7→
 8→    #[cfg(unix)]
 9→    {
10→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
11→            .expect("failed to register SIGTERM handler");
12→        tokio::select! {
13→            _ = ctrl_c => {
14→                tracing::info!("received SIGINT (Ctrl+C)");
15→            },
16→            _ = sigterm.recv() => {
17→                tracing::info!("received SIGTERM");
18→            },
19→        }
20→    }
21→
22→    #[cfg(not(unix))]
23→    {
24→        ctrl_c.await.expect("failed to listen for Ctrl+C");
25→        tracing::info!("received Ctrl+C");
26→    }
27→}
