  5→/// Top-level daemon configuration, typically loaded from `lago.toml`.
  6→#[derive(Debug, Clone, Serialize, Deserialize)]
  7→pub struct DaemonConfig {
  8→    /// Directory for persistent data (journal, blobs, snapshots).
  9→    #[serde(default = "default_data_dir")]
 10→    pub data_dir: PathBuf,
 11→
 12→    /// Path to the policy configuration file.
 13→    #[serde(default = "default_policy_path")]
 14→    pub policy_path: PathBuf,
 15→
 16→    /// Port for the gRPC ingest server.
 17→    #[serde(default = "default_grpc_port")]
 18→    pub grpc_port: u16,
 19→
 20→    /// Port for the HTTP/REST API server.
 21→    #[serde(default = "default_http_port")]
 22→    pub http_port: u16,
 23→
 24→    /// How often (in milliseconds) the WAL flushes buffered events to disk.
 25→    #[serde(default = "default_wal_flush_interval_ms")]
 26→    pub wal_flush_interval_ms: u64,
 27→
 28→    /// Number of buffered events that triggers an immediate WAL flush.
 29→    #[serde(default = "default_wal_flush_threshold")]
 30→    pub wal_flush_threshold: usize,
 31→
 32→    /// Number of events between automatic snapshots.
 33→    #[serde(default = "default_snapshot_interval")]
 34→    pub snapshot_interval: u64,
 35→}
 36→
 37→impl DaemonConfig {
 38→    /// Load configuration from a TOML file.
 39→    ///
 40→    /// If the file does not exist, returns a default config.
 41→    pub fn load(path: &Path) -> Result<Self, Box<dyn std::error::Error>> {
 42→        if !path.exists() {
 43→            tracing::info!(path = %path.display(), "config file not found, using defaults");
 44→            return Ok(Self::default());
 45→        }
 46→
 47→        let contents = std::fs::read_to_string(path)?;
 48→
 49→        // The TOML file may have a [daemon] section — try to parse the top
 50→        // level first, then fall back to extracting the [daemon] table.
 51→        let config: DaemonConfig = match toml::from_str(&contents) {
 52→            Ok(cfg) => cfg,
 53→            Err(_) => {
 54→                // Try extracting from a [daemon] table
 55→                let table: toml::Value = toml::from_str(&contents)?;
 56→                if let Some(daemon) = table.get("daemon") {
 57→                    toml::from_str(&daemon.to_string())?
 58→                } else {
 59→                    toml::from_str(&contents)?
 60→                }
 61→            }
 62→        };
 63→
 64→        tracing::info!(path = %path.display(), "config loaded");
 65→        Ok(config)
 66→    }
 67→
 68→    /// Merge CLI overrides into the config. Non-default CLI values take
 69→    /// precedence over values from the config file.
 70→    pub fn merge_cli(
 71→        &mut self,
 72→        grpc_port: Option<u16>,
 73→        http_port: Option<u16>,
 74→        data_dir: Option<PathBuf>,
 75→    ) {
 76→        if let Some(port) = grpc_port {
 77→            self.grpc_port = port;
 78→        }
 79→        if let Some(port) = http_port {
 80→            self.http_port = port;
 81→        }
 82→        if let Some(dir) = data_dir {
 83→            self.data_dir = dir;
 84→        }
 85→    }
 86→}
 87→
 88→impl Default for DaemonConfig {
 89→    fn default() -> Self {
 90→        Self {
 91→            data_dir: default_data_dir(),
 92→            policy_path: default_policy_path(),
 93→            grpc_port: default_grpc_port(),
 94→            http_port: default_http_port(),
 95→            wal_flush_interval_ms: default_wal_flush_interval_ms(),
 96→            wal_flush_threshold: default_wal_flush_threshold(),
 97→            snapshot_interval: default_snapshot_interval(),
 98→        }
 99→    }
100→}
