 31→struct LakeFsObserver {
 32→    workspace_root: PathBuf,
 33→    journal: Arc<dyn Journal>,
 34→    blob_store: Arc<lago_store::BlobStore>,
 35→}
 36→
 37→#[async_trait::async_trait]
 38→impl arcan_aios_adapters::tools::ToolHarnessObserver for LakeFsObserver {
 39→    async fn post_execute(&self, session_id: String, _tool_name: String) {
 40→        // We skip memory tools since they don't modify the FS directly, and bash since we might want more granular control, but for now we trace everything.
 41→        let sess_id = SessionId::from_string(session_id.clone());
 42→        let branch_id = BranchId::from_string("main");
 43→
 44→        let events = match self
 45→            .journal
 46→            .read(EventQuery::new().session(lago_core::SessionId::from_string(session_id)))
 47→            .await
 48→        {
 49→            Ok(events) => events,
 50→            Err(e) => {
 51→                tracing::warn!(%e, "LakeFsObserver: failed to read journal");
 52→                return;
 53→            }
 54→        };
 55→
 56→        let mut proj = ManifestProjection::new();
 57→        for e in events {
 58→            if e.branch_id == branch_id {
 59→                let _ = proj.on_event(&e);
 60→            }
 61→        }
 62→
 63→        let current_manifest = proj.manifest().clone();
 64→
 65→        let new_manifest =
 66→            match lago_fs::snapshot(&self.workspace_root, &current_manifest, &self.blob_store) {
 67→                Ok(m) => m,
 68→                Err(e) => {
 69→                    tracing::warn!(%e, "LakeFsObserver: failed to snapshot workspace");
 70→                    return;
 71→                }
 72→            };
 73→
 74→        let diffs = lago_fs::diff(&current_manifest, &new_manifest);
 75→        if diffs.is_empty() {
 76→            return;
 77→        }
 78→
 79→        tracing::info!(
 80→            diff_count = diffs.len(),
 81→            "LakeFsObserver: workspace changed, emitting events"
 82→        );
 83→
 84→        for diff in diffs {
 85→            let payload = match diff {
 86→                DiffEntry::Added { path, entry } => EventPayload::FileWrite {
 87→                    path,
 88→                    blob_hash: entry.blob_hash.into(),
 89→                    size_bytes: entry.size_bytes,
 90→                    content_type: entry.content_type,
 91→                },
 92→                DiffEntry::Modified {
 93→                    path, new: entry, ..
 94→                } => EventPayload::FileWrite {
 95→                    path,
 96→                    blob_hash: entry.blob_hash.into(),
 97→                    size_bytes: entry.size_bytes,
 98→                    content_type: entry.content_type,
 99→                },
100→                DiffEntry::Removed { path, .. } => EventPayload::FileDelete { path },
101→            };
102→
103→            let envelope = EventEnvelope {
104→                event_id: EventId::new(),
105→                session_id: sess_id.clone(),
106→                branch_id: branch_id.clone(),
107→                run_id: None,
108→                seq: 0,
109→                timestamp: EventEnvelope::now_micros(),
110→                parent_id: None,
111→                payload,
112→                metadata: std::collections::HashMap::new(),
113→                schema_version: 1,
114→            };
115→
116→            if let Err(e) = self.journal.append(envelope).await {
117→                tracing::warn!(%e, "LakeFsObserver: failed to append event");
118→            }
119→        }
120→    }
121→}
