202→            max_iterations,
203→        } => Some(AgentEvent::RunStarted {
204→            run_id,
205→            session_id,
206→            provider: provider.clone(),
207→            max_iterations: *max_iterations,
208→        }),
209→        ProtocolEventKind::StepStarted { index } => Some(AgentEvent::IterationStarted {
210→            run_id,
211→            session_id,
212→            iteration: *index,
213→        }),
214→        ProtocolEventKind::StepFinished {
215→            index,
