392→impl NetworkClient {
393→    pub fn new(config: NetworkConfig) -> Self {
394→        Self {
395→            client: Client::builder()
396→                .timeout(Duration::from_secs(30))
397→                .build()
398→                .unwrap(),
399→            config,
400→        }
401→    }
402→
403→    /// Submits a message to the agent's run endpoint
404→    pub async fn submit_run(&self, message: &str, branch: Option<&str>) -> anyhow::Result<()> {
405→        let url = format!(
406→            "{}/sessions/{}/runs",
407→            self.config.base_url, self.config.session_id
408→        );
409→
410→        let body = json!({
411→            "objective": message,
412→            "branch": branch,
413→        });
414→
415→        let res = self.client.post(&url).json(&body).send().await?;
416→
417→        if !res.status().is_success() {
418→            let error_text = res.text().await?;
419→            anyhow::bail!("Failed to submit run: {}", error_text);
420→        }
421→
422→        Ok(())
423→    }
424→
425→    /// Submits an approval decision
426→    pub async fn submit_approval(
427→        &self,
428→        approval_id: &str,
429→        decision: &str,
430→        reason: Option<&str>,
431→    ) -> anyhow::Result<()> {
432→        let url = format!(
433→            "{}/sessions/{}/approvals/{}",
434→            self.config.base_url, self.config.session_id, approval_id
435→        );
436→        let approved = matches!(
437→            decision.to_ascii_lowercase().as_str(),
438→            "approved" | "approve" | "yes" | "y" | "true"
439→        );
440→        let actor = reason.unwrap_or("tui");
441→
442→        let body = json!({
443→            "approved": approved,
444→            "actor": actor,
445→        });
446→
447→        let res = self.client.post(&url).json(&body).send().await?;
448→
449→        if !res.status().is_success() {
450→            let error_text = res.text().await?;
451→            anyhow::bail!("Failed to submit approval: {}", error_text);
452→        }
453→
454→        Ok(())
455→    }
456→
457→    /// Fetches the currently selected model from the daemon.
458→    pub async fn get_model(&self) -> anyhow::Result<String> {
459→        anyhow::bail!("Model inspection is not exposed in the canonical session API")
460→    }
461→
462→    /// Switches the active provider/model in the daemon.
463→    pub async fn set_model(&self, provider: &str, model: Option<&str>) -> anyhow::Result<String> {
464→        let requested = match model {
465→            Some(model) => format!("{provider}:{model}"),
466→            None => provider.to_string(),
467→        };
468→        anyhow::bail!("Model switching ({requested}) is not exposed in the canonical session API")
469→    }
470→
471→    /// Continuously listens to the SSE stream and pushes parsed events to the channel
472→    pub async fn listen_events(&self, sender: mpsc::Sender<AgentEvent>) -> anyhow::Result<()> {
473→        let url = format!(
474→            "{}/sessions/{}/events/stream?branch=main&cursor=0&format=vercel_ai_sdk_v6",
475→            self.config.base_url, self.config.session_id
476→        );
477→
478→        let mut es = EventSource::get(url);
479→
480→        while let Some(event) = es.next().await {
481→            match event {
482→                Ok(Event::Open) => {
483→                    tracing::info!("SSE Connection Opened");
484→                }
485→                Ok(Event::Message(message)) => {
486→                    let event_name = message.event.as_str();
487→                    let data = message.data.trim();
488→                    if event_name == "done" || data == "[DONE]" || data == "{\"type\": \"done\"}" {
489→                        continue;
490→                    }
491→
492→                    if let Some(agent_event) =
493→                        parse_protocol_record(data).or_else(|| parse_vercel_v6_part(data))
494→                    {
495→                        if sender.send(agent_event).await.is_err() {
496→                            break;
497→                        }
498→                    } else if let Some(agent_event) =
499→                        parse_canonical_event(event_name, data, &self.config.session_id)
500→                    {
501→                        if sender.send(agent_event).await.is_err() {
502→                            break;
503→                        }
504→                    } else {
505→                        tracing::debug!("Ignored SSE event '{}': {}", event_name, data);
506→                    }
507→                }
508→                Err(EventSourceError::StreamEnded) => {
509→                    tracing::debug!("SSE stream ended; waiting for reconnect");
510→                    tokio::time::sleep(Duration::from_millis(250)).await;
511→                }
512→                Err(e) => {
513→                    tracing::warn!("SSE stream error: {}", e);
514→                    tokio::time::sleep(Duration::from_secs(1)).await;
515→                }
516→            }
517→        }
518→        Ok(())
519→    }
520→}
